// DANGEROUS: user input flows straight into the query string.
const q = `SELECT * FROM users WHERE email = '${req.body.email}'`;
await db.query(q);  // ' OR '1'='1 ...  -> auth bypass / dump

// SAFE: parameterized query — the driver separates code from data.
await db.query(
  'SELECT * FROM users WHERE email = $1',
  [req.body.email]
);

// The submitted change.
app.get('/invoices/:id', async (req, res) => {
  const invoice = await db.query(
    `SELECT * FROM invoices WHERE id = ${req.params.id}`
  );
  res.json(invoice.rows[0]);
});

// After review.
