  const { rows } = await db.query(
    'SELECT * FROM invoices WHERE id = $1 AND owner_id = $2',
    [req.params.id, req.user.id]
  );
  if (rows.length === 0) return res.sendStatus(404);
  res.json(rows[0]);
});

challenges.prompt:
You are reviewing a Node/Express endpoint that returns a document by id. CI is green (lint passes, one happy-path test passes). Identify every blocking issue and rewrite the handler to fix them. Original code:

app.get('/docs/:id', async (req, res) => {
  const id = req.params.id;
  const doc = await db.query('SELECT * FROM docs WHERE id = ' + id);
  res.json(doc.rows[0]);
});

challenges.solutionCode:
// Blocking issues found in review:
//  1. SQL injection: req.params.id is string-concatenated into the query.
//  2. Broken access control (IDOR): no check that the caller owns the doc.
//  3. Correctness: rows[0] is undefined on no match -> returns 200 with null.
//  (nit, non-blocking: handler should live in the docs module, not app root.)

const express = require('express');
const app = express();

// requireAuth populates req.user from a verified session/JWT (assumed middleware).
app.get('/docs/:id', requireAuth, async (req, res) => {
  // Fix 1: parameterized query — driver separates code from data.
  // Fix 2: scope the row to the authenticated owner.
  const { rows } = await db.query(
    'SELECT * FROM docs WHERE id = $1 AND owner_id = $2',
    [req.params.id, req.user.id]
  );

  // Fix 3: 404 when nothing matches (also avoids leaking existence to non-owners).
  if (rows.length === 0) {
    return res.sendStatus(404);
  }

  res.json(rows[0]);
});

module.exports = app;

// A) blocking, names the failing condition and asks for the guard:
// "blocking: this throws when `items` is empty because we index items[0]
//  before the length check. Can we guard for the empty case and return [] ?"

// B) blocking but about the code path, no personal jab, states the why:
// "blocking: the network call on line 42 can reject (timeout / 5xx) and
//  nothing catches it, so the request hangs. What should happen on failure
//  here \u2014 retry, or surface a 503 to the caller?"

// C) non-blocking nit with a concrete suggestion and rationale:
// "nit: `data` is hard to follow three screens down \u2014 maybe `pendingOrders`
//  so the type is obvious at the call site? Non-blocking."

// D) question first (the author may have a reason), with the why:
// "A map keyed by id would make this lookup O(1) instead of the current
//  O(n) scan inside the loop, which matters at our order volumes. Was there
//  a reason for the linear search, or shall we switch it? (optional)"

// Principles applied to every rewrite:
//  - critique the code, never the author (drop 'you always')
//  - explain the why (teaches, and is easier to accept)
//  - ask when uncertain; decree only when certain and it is blocking
//  - prefix blocking vs nit/optional so the merge gate is unambiguous
const principles = [
  'code-not-person',
  'explain-why',
  'ask-when-uncertain',
  'label-blocking-vs-nit'
];
